USE graduate_match;
SET NAMES utf8mb4;
START TRANSACTION;
ON DUPLICATE KEY UPDATE full_name = VALUES(full_name), gender = VALUES(gender), college_id = VALUES(college_id), major_id = VALUES(major_id), graduation_year = VALUES(graduation_year), email = VALUES(email), phone = VALUES(phone), resume_text = VALUES(resume_text), technical_projects_text = VALUES(technical_projects_text), capability_summary_text = VALUES(capability_summary_text);
COMMIT;
